prompt_a:
Here is eBPF code that fails verification. Fix it.

Code:
struct provenance_structure {
__u8 to_trace;
struct bpf_spin_lock lock;
};
struct {
__uint(type, BPF_MAP_TYPE_TASK_STORAGE);
__uint(map_flags, BPF_F_NO_PREALLOC);
__type(key, int);
__type(value, struct provenance_structure);
} provenance_structure_map_task SEC(".maps");
SEC("lsm/task_alloc")
int BPF_PROG(task_allocation, struct task_struct *p, u64 clone_flags) {
struct provenance_structure *prov;
prov = bpf_task_storage_get(&provenance_structure_map_task, p, NULL, 0);
if(prov){
bpf_spin_lock(&prov->lock);
prov->to_trace = 1;
bpf_spin_unlock(&prov->lock);
}
return 0;
}
However, if I try to get the BPF storage for the current task instead of the p argument, it fails to attach:
SEC("lsm/task_alloc")
int BPF_PROG(task_allocation, struct task_struct *p, u64 clone_flags) {
// casting the task to (struct task_struct *) yields the same error
struct task_struct *s_task = (void *)bpf_get_current_task();
struct provenance_structure *prov;
prov = bpf_task_storage_get(&provenance_structure_map_task, s_task, NULL, 0);
if(prov){
bpf_spin_lock(&prov->lock);
// store a provenance_structure to the inode, with the to_trace flag set to True
prov->to_trace = 1; // true
bpf_spin_unlock(&prov->lock);
}
return 0;
}
The verifier log shows that, the function bpf_task_storage_get expects as second argument a pointer or a trusted pointer, instead it perceives s_task as a scalar:

